def chocolate_distribution(packets, num_students):
    n = len(packets)

    if num_students == 0 or n == 0:
        return 0

    if num_students > n:
        return -1

    packets.sort()

    min_diff = float('inf')

    for i in range(n - num_students + 1):
        current_diff = packets[i + num_students - 1] - packets[i]
        min_diff = min(min_diff, current_diff)

    return min_diff
